using sv_e84317dc58c042eaa67820896c7255ad.Components;
using sv_e84317dc58c042eaa67820896c7255ad.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Ensure every browser gets a stable session key via cookie.
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.ContainsKey("WizardSessionId"))
    {
        var id = Guid.NewGuid().ToString("N");
        context.Response.Cookies.Append("WizardSessionId", id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
        context.Items["WizardSessionId"] = id;
    }
    else
    {
        context.Items["WizardSessionId"] = context.Request.Cookies["WizardSessionId"];
    }
    await next();
});

app.UseAntiforgery();

