using Microsoft.AspNetCore.Components;
using sv_e84317dc58c042eaa67820896c7255ad.Services;

namespace sv_e84317dc58c042eaa67820896c7255ad.Components.Pages.Apply;

/// <summary>
/// Base class for wizard pages. Captures the session key during prerender
/// (when HttpContext is available) and provides access to the shared state.
/// </summary>
public abstract class WizardPageBase : ComponentBase
{
    [Inject] protected WizardStateStore StateStore { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    protected WizardState Wizard { get; private set; } = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        // During prerender (SSR), HttpContext is available — capture the session key.
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is not null)
        {
            _sessionId = ctx.Items["WizardSessionId"]?.ToString() ?? "";
        }

        if (!string.IsNullOrEmpty(_sessionId))
        {
            Wizard = StateStore.GetOrCreate(_sessionId);
        }
    }

    protected void MarkCompleteAndNavigate(int completedStep, string nextUrl)
    {
        Wizard.CompletedSteps.Add(completedStep);
        Nav.NavigateTo(nextUrl, forceLoad: false);
    }
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Apply – Personal Info</PageTitle>
<h3>Step 1: Personal Information</h3>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private void Next() => MarkCompleteAndNavigate(1, "/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_e84317dc58c042eaa67820896c7255ad.Services

<PageTitle>Apply – Experience</PageTitle>
<h3>Step 2: Work Experience</h3>

@foreach (var job in Wizard.Jobs)
{
    <div class="card mb-2 p-2">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/personal-info")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddJob() => Wizard.Jobs.Add(new JobEntry());
    private void Next() => MarkCompleteAndNavigate(2, "/apply/references");
}

@page "/apply/references"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_e84317dc58c042eaa67820896c7255ad.Services

<PageTitle>Apply – References</PageTitle>
<h3>Step 3: References</h3>

@foreach (var r in Wizard.References)
{
    <div class="card mb-2 p-2">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="r.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="r.Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Phone</label>
            <input class="form-control" @bind="r.Phone" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/experience")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddRef() => Wizard.References.Add(new Reference());
    private void Next() => MarkCompleteAndNavigate(3, "/apply/review");
}

@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Apply – Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Info</h5>
    <p><strong>Name:</strong> @Wizard.FullName</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @if (Wizard.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    @foreach (var job in Wizard.Jobs)
    {
        <p>@job.Title at @job.Company (@job.Years years)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Relationship (@r.Phone)</p>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private void Submit()
    {
        Wizard.CompletedSteps.Add(4);
        // In a real app, persist to a database here, then navigate to a confirmation page.
        Nav.NavigateTo("/");
    }
}

